window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["z"]={"Zbigniew": "<b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zdzisław": "<b>Zdzisław</b>, <i><b>Zdziesław</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zdzie (Zdzi-)</i> (\"uczynić, zdziałać, zrobić\") i <i>-sław</i> (\"sława\"). Zanotowane w dokumentach z roku 1198.", "Zygmunt": "<b>Zygmunt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie oraz <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się ze słów: <i>sigu</i> oznaczającego „zwycięstwo” i <i>mund</i> lub <i>munt</i>, „opieka”, „tarcza”. Można je zatem tłumaczyć jako „obrona przez zwycięstwo”.", "Zenon": "<b>Zenon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało jako forma skrócona greckich imion złożonych typu <i>Zenodoros</i>, <i>Zenodotos</i>, oznaczających \"dar <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>\".", "Zygfryd": "<b>Zygfryd</b>, <b>Sygurd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>sigu</i> i <i>fridu</i> oznaczających <i>zwycięstwo</i> i <i>opieka</i>, jako ten, który zapewnia bezpieczeństwo swym podopiecznym. Imię to było znane w Polsce od średniowiecza, m.in. w formach: Zebrzyd, Zybrzyd, Zewrzyd, Zywrzyd. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Zygfryda\" target=\"_blank\" rel=\"noopener noreferrer\">Zygfryda</a>.", "Ziemowit": "<b>Ziemowit</b> – zniekształcona forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Siemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Siemowit</a> oznaczającego „głowę rodu”.", "Zbysław": "<b>Zbysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-sław</i>.", "Zachariasz": "<b>Zachariasz</b>, <b>Zachary</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa זְכַרְיָה (<i>zecharja</i>) znaczącego „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> pamięta”. Forma Zachary była nadawana bardzo rzadko, ale występowała w polszczyźnie co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII wieku</a>. Kościół katolicki zna 11 świętych o tym imieniu; są to w większości prorocy z czasów <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">starotestamentowych</a>. Jeden z nich jest autorem biblijnej <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Zachariasza\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Zachariasza</a>.", "Zbyszko": "<b>Zbyszko</b> – zdrobnienie od imion <a href=\"https://pl.wikipedia.org/wiki/Zbigniew\" target=\"_blank\" rel=\"noopener noreferrer\">Zbygniew</a>, <a href=\"https://pl.wikipedia.org/wiki/Zbys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zbysław</a>, <a href=\"https://pl.wikipedia.org/wiki/Zbylut\" target=\"_blank\" rel=\"noopener noreferrer\">Zbylut</a> i <a href=\"https://pl.wikipedia.org/wiki/Zbywoj\" target=\"_blank\" rel=\"noopener noreferrer\">Zbywoj</a>. Obecnie bywa nadawane jako samodzielne imię.", "Zenobiusz": "<b>Zenobiusz</b>, <b>Zenobi</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>Dzeno-</i> (<a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">homerycka</a> forma imienia <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>) i <i>bios</i> („życie”). Wymowa <i>Zenobios</i>, zamiast pierwotnej <i>Dzenobios</i>, pochodzi z czasów rzymskich.", "Zoran": "<b>Zoran</b> (<a href=\"https://pl.wikipedia.org/wiki/Cyrylica_serbska\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylica serbska</a>: Зоран) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskie</a>, wywodzące się od słowa <i>zora</i> czyli „zorza, świt, jutrznia”.", "Zoltán": "Zoltán poślubił nieznaną z imienia księżniczkę <a href=\"https://pl.wikipedia.org/wiki/Morawy\" target=\"_blank\" rel=\"noopener noreferrer\">morawską</a>, przypuszczalnie córkę <a href=\"https://pl.wikipedia.org/wiki/Mojmir_II\" target=\"_blank\" rel=\"noopener noreferrer\">Mojmira II</a>.", "Zawisza": "<b>Zawisza</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">cz.</a>&#160;<em>Záviš</em>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Zaviša) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starosłowiańskie imię</a> męskie. Wywodzi się od słowa oznaczającego „zazdrosny o sławę”.", "Zoltan": "Zoltán poślubił nieznaną z imienia księżniczkę <a href=\"https://pl.wikipedia.org/wiki/Morawy\" target=\"_blank\" rel=\"noopener noreferrer\">morawską</a>, przypuszczalnie córkę <a href=\"https://pl.wikipedia.org/wiki/Mojmir_II\" target=\"_blank\" rel=\"noopener noreferrer\">Mojmira II</a>.", "Zefiryn": "<b>Zefiryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Jest to imię <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>, utworzone za pomocą sufiksu <i>-inus</i> od imienia greckiego boga wiatru zachodniego, <a href=\"https://pl.wikipedia.org/wiki/Zefir\" target=\"_blank\" rel=\"noopener noreferrer\">Zefira</a> (gr. <i>Zéphyros</i>).", "Zlatan": "<b>Zlatan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Златан) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Popularne jest zwłaszcza wśród narodów <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskich</a>; <a href=\"https://pl.wikipedia.org/wiki/Chorwaci\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwatów</a>, <a href=\"https://pl.wikipedia.org/wiki/Serbowie\" target=\"_blank\" rel=\"noopener noreferrer\">Serbów</a>, <a href=\"https://pl.wikipedia.org/wiki/Boszniacy\" target=\"_blank\" rel=\"noopener noreferrer\">Boszniaków</a>, <a href=\"https://pl.wikipedia.org/wiki/Macedo%C5%84czycy\" target=\"_blank\" rel=\"noopener noreferrer\">Macedończyków</a>, <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarów</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owe%C5%84cy\" target=\"_blank\" rel=\"noopener noreferrer\">Sloweńców</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_po%C5%82udniowos%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskiego</a> słowa <i>zlato</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;злато) oznaczającego w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a> <i><a href=\"https://pl.wikipedia.org/wiki/Z%C5%82oto\" target=\"_blank\" rel=\"noopener noreferrer\">złoto</a></i>. Zdrobnienie imienia Zlatan to Zlatko, używane jest również jako samodzielne imię. Żeńskie formy tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Zlata\" target=\"_blank\" rel=\"noopener noreferrer\">Zlata</a> i Zlatica.", "Zohar": "Jest napisany po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejsku</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a>. Dzieło spisał prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz_ben_Szem_Tow\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesz z Leonu</a>, ale zawiera ono także fragmenty wcześniejszego pochodzenia. Środowiska ortodoksyjne przypisują autorstwo Zoharu <a href=\"https://pl.wikipedia.org/wiki/Szymon_bar_Jochaj\" target=\"_blank\" rel=\"noopener noreferrer\">Szymonowi bar Jochajowi</a>, <a href=\"https://pl.wikipedia.org/wiki/Tannaici\" target=\"_blank\" rel=\"noopener noreferrer\">tanaicie</a> z II wieku. Poza komentarzami do wspomnianych ksiąg zawiera rozważania, interpretacje <a href=\"https://pl.wikipedia.org/wiki/Halacha\" target=\"_blank\" rel=\"noopener noreferrer\"><i>halachy</i></a>, traktaty o <a href=\"https://pl.wikipedia.org/wiki/Chiromancja\" target=\"_blank\" rel=\"noopener noreferrer\">chiromancji</a> i fragmenty filozoficzno-mistyczne. Do dziś pozostaje podstawowym tekstem żydowskiej <a href=\"https://pl.wikipedia.org/wiki/Mistycyzm\" target=\"_blank\" rel=\"noopener noreferrer\">mistyki</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej</a> <a href=\"https://pl.wikipedia.org/wiki/Kaba%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">kabały</a>. Poruszane są w nim zagadnienia natury <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a>, powstania i kształtu świata, natury <a href=\"https://pl.wikipedia.org/wiki/Dusza_(religia)\" target=\"_blank\" rel=\"noopener noreferrer\">duszy</a>, <a href=\"https://pl.wikipedia.org/wiki/Grzech\" target=\"_blank\" rel=\"noopener noreferrer\">grzechu</a>, <a href=\"https://pl.wikipedia.org/wiki/Zbawienie\" target=\"_blank\" rel=\"noopener noreferrer\">odkupienia</a>, <a href=\"https://pl.wikipedia.org/wiki/Dobro\" target=\"_blank\" rel=\"noopener noreferrer\">dobra</a> i <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">zła</a> oraz pokrewne.", "Żelisław": "Od tego imienia pochodzi nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/%C5%BBelech%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Żelechów</a>.", "Zacheusz": "<b>Zacheusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia hebrajskiego, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>כָּי (Zakkai)</i>, co oznacza „czysty”. Wśród patronów tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Zacheusz_z_Jerozolimy\" target=\"_blank\" rel=\"noopener noreferrer\">św. Zacheusz</a>, biskup <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolimy</a>. Znany jest także <a href=\"https://pl.wikipedia.org/wiki/Zacheusz_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Zacheusz</a> z <a href=\"https://pl.wikipedia.org/wiki/Ewangelia_%C5%81ukasza\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii św. Łukasza</a>, który chcąc zobaczyć <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a> wspiął się w <a href=\"https://pl.wikipedia.org/wiki/Jerycho\" target=\"_blank\" rel=\"noopener noreferrer\">Jerychu</a> na <a href=\"https://pl.wikipedia.org/wiki/Figowiec_sykomora\" target=\"_blank\" rel=\"noopener noreferrer\">sykomorę</a>.", "Zyndram": "<b>Zyndram</b> – imię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe ze słów <i>sind</i> i <i>Rabe</i> (co w tłumaczeniu na język polski oznacza kruka), raczej rzadko spotykane. Imię to nosił jeden z dowódców polskiego rycerstwa w bitwie pod Grunwaldem, <a href=\"https://pl.wikipedia.org/wiki/Zyndram_z_Maszkowic\" target=\"_blank\" rel=\"noopener noreferrer\">Zyndram z Maszkowic</a>.", "Ziemisław": "<b>Siemisław</b>, <b>Siemosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-sław</i> („sława”). Imię to wyraża życzenie sławy w przestrzeni rodzinnej.", "Zygbert": "<b>Zybert</b>, <b>Zybracht</b>, <b>Zybart</b>, <b>Zygbert</b>, Zygisbert – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> germańskie, notowane w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1480\" target=\"_blank\" rel=\"noopener noreferrer\">1480</a> roku w formach <b>Zybart</b> i <b>Zybert</b>. Pierwszym członem imienia jest <i>sig</i>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>sigi</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>sigu</i> — \"zwycięstwo\" albo <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>sigis</i>. Forma ściągnięta <i>sī</i> &lt; <i>sii</i> powstała bardzo wcześnie na terenach <a href=\"https://pl.wikipedia.org/wiki/Frankonia\" target=\"_blank\" rel=\"noopener noreferrer\">zachodniofrankońskich</a> na skutek zaniku międzywokalicznego <i>-g-</i>. Drugi człon imienia, <i>-bert</i>, wywodzi się z pnia <i>bercht</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>berhta</i> — \"jasny\". Forma <i>-bert</i>, pozbawiona śródgłosowego <i>-h-</i>, jest charakterystyczna dla <a href=\"https://pl.wikipedia.org/wiki/Antroponimia\" target=\"_blank\" rel=\"noopener noreferrer\">nazw osobowych</a> przekazywanych przez <a href=\"https://pl.wikipedia.org/wiki/Pi%C5%9Bmiennictwo\" target=\"_blank\" rel=\"noopener noreferrer\">piśmiennictwo</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, zaś forma <i>-bart</i> jest wynikiem obniżenia <i>e</i> &gt; <i>a</i>. Niektóre możliwe staropolskie zdrobnienia: Zyka, Zyc.", "Żytomir": "<b>Żytomir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Znaczenie imienia: „pragnący żyć w pokoju”", "Zenobi": "<b>Zenobiusz</b>, <b>Zenobi</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>Dzeno-</i> (<a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">homerycka</a> forma imienia <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>) i <i>bios</i> („życie”). Wymowa <i>Zenobios</i>, zamiast pierwotnej <i>Dzenobios</i>, pochodzi z czasów rzymskich.", "Żegota": "<b>Żegota</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Wywodzi się od słowa <i>żec</i> (czyli „palić”). Imię Żegota uważano za polskie tłumaczenie imienia <a href=\"https://pl.wikipedia.org/wiki/Ignacy\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy</a> (ze względu na podobieństwo znaczeniowe do łacińskiego <i>ignis</i> – „ogień”). Pojawiło się jednak w polskich zapisach w <a href=\"https://pl.wikipedia.org/wiki/1212\" target=\"_blank\" rel=\"noopener noreferrer\">1212</a> roku, a więc ponad sto lat wcześniej niż Ignacy.", "Zbylut": "<b>Zbylut</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> (również w odmianie Zbijlud i Zbilut), męskie, złożone z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-lut</i> („srogi, ostry”). Mogło oznaczać „tego, który pozbył się srogości”.", "Zef": "<b>Zef</b> – <a href=\"https://pl.wikipedia.org/wiki/Kontrkultura\" target=\"_blank\" rel=\"noopener noreferrer\">kontrkultura</a> wywodząca się z <a href=\"https://pl.wikipedia.org/wiki/Po%C5%82udniowa_Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Republiki Południowej Afryki</a>. Słowo <i>zef</i> pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_afrikaans\" target=\"_blank\" rel=\"noopener noreferrer\">południowoafrykańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Slang\" target=\"_blank\" rel=\"noopener noreferrer\">slangu</a> i oznacza w wolnym tłumaczeniu „wspólny”, „powszechny”, „ogólny”. Jack Parow, raper z <a href=\"https://pl.wikipedia.org/wiki/Kapsztad\" target=\"_blank\" rel=\"noopener noreferrer\">Kapsztadu</a>, w wywiadzie mówi o zef: „<i>coś jakby ekskluzywny, ale przeciwieństwo ekskluzywnego”.</i> Yo-landi Visser, raperka z grupy <a href=\"https://pl.wikipedia.org/wiki/Die_Antwoord\" target=\"_blank\" rel=\"noopener noreferrer\">Die Antwoord</a>, określa to tak: „Jesteś <i>zef</i> wtedy, kiedy jesteś biedny, ale <i>fancy</i>. Biedny, ale seksowny, kiedy masz styl”.", "Zeno": "Dowodził wojskami w <a href=\"https://pl.wikipedia.org/wiki/Antiochia\" target=\"_blank\" rel=\"noopener noreferrer\">Antiochii</a>. Przyczynił się do upadku wszechwładnego wodza, <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alana</a> <a href=\"https://pl.wikipedia.org/wiki/Flawiusz_Ardaburiusz_Aspar\" target=\"_blank\" rel=\"noopener noreferrer\">Aspara</a> w <a href=\"https://pl.wikipedia.org/wiki/471\" target=\"_blank\" rel=\"noopener noreferrer\">471</a>. Za panowania swego syna <a href=\"https://pl.wikipedia.org/wiki/Leon_II_(cesarz)\" target=\"_blank\" rel=\"noopener noreferrer\">Leona II Małego</a> występował w jego imieniu jako <a href=\"https://pl.wikipedia.org/wiki/Regent\" target=\"_blank\" rel=\"noopener noreferrer\">regent</a>. W <a href=\"https://pl.wikipedia.org/wiki/475\" target=\"_blank\" rel=\"noopener noreferrer\">475</a> utracił władzę w wyniku rewolty <a href=\"https://pl.wikipedia.org/wiki/Bazyliskus\" target=\"_blank\" rel=\"noopener noreferrer\">Bazyliskusa</a>, który ogłosił się cesarzem. W sierpniu <a href=\"https://pl.wikipedia.org/wiki/476\" target=\"_blank\" rel=\"noopener noreferrer\">476</a> wkroczył do <a href=\"https://pl.wikipedia.org/wiki/Konstantynopol\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantynopola</a>, usunął Bazyliskusa i odzyskał władzę. W <a href=\"https://pl.wikipedia.org/wiki/477\" target=\"_blank\" rel=\"noopener noreferrer\">477</a> roku kazał zamordować <a href=\"https://pl.wikipedia.org/wiki/Armatus\" target=\"_blank\" rel=\"noopener noreferrer\">Armatusa</a>. Pełnił urząd <a href=\"https://pl.wikipedia.org/wiki/Konsul_rzymski\" target=\"_blank\" rel=\"noopener noreferrer\">konsula</a> w 479 . W tym samym roku <a href=\"https://pl.wikipedia.org/wiki/Odoaker\" target=\"_blank\" rel=\"noopener noreferrer\">Odoaker</a> odesłał mu insygnia cesarskie <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_zachodniorzymskie\" target=\"_blank\" rel=\"noopener noreferrer\">z zachodu</a> i uznał jego formalne zwierzchnictwo. Mimo tego, Zeno poparł później przeciwko Odoakrowi władcę <a href=\"https://pl.wikipedia.org/wiki/Ostrogoci\" target=\"_blank\" rel=\"noopener noreferrer\">Ostrogotów</a> <a href=\"https://pl.wikipedia.org/wiki/Teodoryk_Wielki\" target=\"_blank\" rel=\"noopener noreferrer\">Teodoryka</a>, który <a href=\"https://pl.wikipedia.org/wiki/Podb%C3%B3j_Italii_przez_Got%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">w 489 najechał Italię</a>, w 493 usunął rywala i założył w niej <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Ostrogot%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">własne królestwo</a>.", "Żywisław": "<b>Żywisław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> utworzony na wzór imion <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskich</a>. Nienotowane w źródłach <a href=\"https://pl.wikipedia.org/wiki/Staropolszczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskich</a>. Człon <i>Żywi-</i> jest niespotykany w staropolskich imionach dwuczłonowych.", "Zoe": "<b>Zoe</b>, <b>Zoja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające „życie” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ζωή). W postaci <i>Zoja</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Зоя) imię to występuje przede wszystkim w krajach <a href=\"https://pl.wikipedia.org/wiki/Europa_Wschodnia\" target=\"_blank\" rel=\"noopener noreferrer\">wschodnioeuropejskich</a>.", "Zen": "<b>Zen</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;禅&#59; cicha medytacja, religijna kontemplacja, z <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">skt.</a> ध्यान <i>Dhyāna</i>, poprzez <a href=\"https://pl.wikipedia.org/wiki/Tradycyjne_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chin. trad.</a> 禪那, <a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chin. upr.</a> 禅那, 禅, <a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a>: <i>chánnà</i>, <i><a href=\"https://pl.wikipedia.org/wiki/Chan_(buddyzm)\" target=\"_blank\" rel=\"noopener noreferrer\">chán</a></i>) – nurt <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmu</a>, który w pełni rozwiniętą formę uzyskał w <a href=\"https://pl.wikipedia.org/wiki/Chiny_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Chinach</a> (zob. <a href=\"https://pl.wikipedia.org/wiki/Chan_(buddyzm)\" target=\"_blank\" rel=\"noopener noreferrer\">chan</a>), skąd przedostał się do <a href=\"https://pl.wikipedia.org/wiki/Korea\" target=\"_blank\" rel=\"noopener noreferrer\">Korei</a>, <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamu</a> i <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>. Wywodzi się z rodziny buddyzmu <a href=\"https://pl.wikipedia.org/wiki/Mahajana\" target=\"_blank\" rel=\"noopener noreferrer\">mahajany</a>, ale na przestrzeni wieków nabrał wyrazistego indywidualnego stylu, pełnego minimalizmu i zamierzonych <a href=\"https://pl.wikipedia.org/wiki/Paradoks\" target=\"_blank\" rel=\"noopener noreferrer\">paradoksów</a>.", "Zulfikar": "<i>Zulfikar</i> (też w innych wariantach fonetycznych i ortograficznych) jest również często nadawanym w krajach arabskojęzycznych imieniem, nosił je na przykład <a href=\"https://pl.wikipedia.org/wiki/Zulfikar_Ali_Bhutto\" target=\"_blank\" rel=\"noopener noreferrer\">Zulfikar Ali Bhutto</a>, w latach 1971–1973 prezydent, a w 1973–1977 – premier <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistanu</a>.", "Zadar": "<b>Zadar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Za-</i> (być może tu: \"jako\") i <i>-dar</i> (\"upominek, dar, ofiara\"). Mogło oznaczać \"tego, kto pojawił się jako dar\", \"tego, kto jest darem\".", "Zine": "<b>Zin</b>, <b>fanzin</b> (skrót od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>fan magazine</em>) – rodzaj nieprofesjonalnego pisma tworzonego przez osobę bądź grupę osób – miłośników jakiegoś tematu (np. <a href=\"https://pl.wikipedia.org/wiki/Muzyka\" target=\"_blank\" rel=\"noopener noreferrer\">muzyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Literatura\" target=\"_blank\" rel=\"noopener noreferrer\">literatury</a>, <a href=\"https://pl.wikipedia.org/wiki/Fantastyka\" target=\"_blank\" rel=\"noopener noreferrer\">fantastyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Gra_fabularna\" target=\"_blank\" rel=\"noopener noreferrer\">gier fabularnych</a>, <a href=\"https://pl.wikipedia.org/wiki/Ekologia\" target=\"_blank\" rel=\"noopener noreferrer\">ekologii</a>, <a href=\"https://pl.wikipedia.org/wiki/Polityka\" target=\"_blank\" rel=\"noopener noreferrer\">polityki</a>), skierowane do osób podzielających owe zainteresowania.", "Zhuang": "<b>Zhuang</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiń.</a> 壮族 <a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a>: Zhuàngzú) inaczej <b>Zhuangowie</b>, <b>Czuangowie</b> – <a href=\"https://pl.wikipedia.org/wiki/Nar%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">naród</a> <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">azjatycki</a> pochodzenia środkowotajskiego, osiadły w południowych <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chinach</a> i północnym <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamie</a> (<a href=\"https://pl.wikipedia.org/wiki/N%C3%B9ng\" target=\"_blank\" rel=\"noopener noreferrer\">Nùngowie</a>). Najliczniejsza <a href=\"https://pl.wikipedia.org/wiki/Mniejszo%C5%9Bci_narodowe_w_Chi%C5%84skiej_Republice_Ludowej\" target=\"_blank\" rel=\"noopener noreferrer\">mniejszość etniczna Chińskiej Republiki Ludowej</a> (ok. 18 mln os.). Przeważnie zamieszkują <a href=\"https://pl.wikipedia.org/wiki/Kuangsi\" target=\"_blank\" rel=\"noopener noreferrer\">Region Autonomiczny Kuangsi–Czuang</a> oraz prowincje <a href=\"https://pl.wikipedia.org/wiki/Junnan\" target=\"_blank\" rel=\"noopener noreferrer\">Junnan</a>, <a href=\"https://pl.wikipedia.org/wiki/Guangdong\" target=\"_blank\" rel=\"noopener noreferrer\">Guangdong</a>, <a href=\"https://pl.wikipedia.org/wiki/Kuejczou\" target=\"_blank\" rel=\"noopener noreferrer\">Kuejczou</a> i <a href=\"https://pl.wikipedia.org/wiki/Hunan\" target=\"_blank\" rel=\"noopener noreferrer\">Hunan</a>. Wyróżnia się dwa zespoły pomniejszych grup etnicznych: północnych i południowych Zhuangów. Posługują się <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_zhuang\" target=\"_blank\" rel=\"noopener noreferrer\">językiem zhuang</a>, zróżnicowanym gwarowo.", "Zofia": "<b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Z": "<b>Z</b> (<i>zet</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>z</b>) – dwudziesta szósta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, trzydziesta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Litera ta pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">fenickiej</a> (północno-zachodnio-semickiej) litery zaîn, poprzez <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecką literę</a> ζ (<a href=\"https://pl.wikipedia.org/wiki/Dzeta\" target=\"_blank\" rel=\"noopener noreferrer\">dzeta</a>, zeta). W języku polskim oznacza spółgłoskę przedniojęzykowo-zębową, szczelinową, dźwięczną [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">z̪</a>], w języku niemieckim [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarto-szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʦ</a>], a w hiszpańskim [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_mi%C4%99dzyz%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">θ</a>].", "Zi": "<b>Zi</b> – <a href=\"https://pl.wikipedia.org/wiki/Dwuznak\" target=\"_blank\" rel=\"noopener noreferrer\">dwuznak</a> występujący w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">języku polskim</a>, oznacza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">literę</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%B9\" target=\"_blank\" rel=\"noopener noreferrer\">ź</a> z samogłoską <a href=\"https://pl.wikipedia.org/wiki/A\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>, <a href=\"https://pl.wikipedia.org/wiki/%C4%84\" target=\"_blank\" rel=\"noopener noreferrer\">ą</a>, <a href=\"https://pl.wikipedia.org/wiki/E\" target=\"_blank\" rel=\"noopener noreferrer\">e</a>, <a href=\"https://pl.wikipedia.org/wiki/%C4%98\" target=\"_blank\" rel=\"noopener noreferrer\">ę</a>, <a href=\"https://pl.wikipedia.org/wiki/I\" target=\"_blank\" rel=\"noopener noreferrer\">i</a>, <a href=\"https://pl.wikipedia.org/wiki/O\" target=\"_blank\" rel=\"noopener noreferrer\">o</a>, <a href=\"https://pl.wikipedia.org/wiki/U\" target=\"_blank\" rel=\"noopener noreferrer\">u</a>, w niektórych przypadkach <i>zi</i> wymawia się jak <i>zji</i>, w przykładzie słów nazw własnych na przykład przy słowie <a href=\"https://pl.wikipedia.org/wiki/Zimbabwe\" target=\"_blank\" rel=\"noopener noreferrer\">Zimbabwe</a> (kraju położonego w <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryce</a>), gdzie dźwiękiem pierwszej litery słowa nie brzmi <i>ź</i>, lecz <a href=\"https://pl.wikipedia.org/wiki/Palatalizacja\" target=\"_blank\" rel=\"noopener noreferrer\">zmiękczone</a> <a href=\"https://pl.wikipedia.org/wiki/Z\" target=\"_blank\" rel=\"noopener noreferrer\">z</a>. W pozostałych językach <i>zi</i> to nie dwuznak tylko 2 oddzielne litery.", "Zhonghe": "Populacja dzielnicy Zhonghe w 2016 roku liczyła 414&#160;266 mieszkańców – 212&#160;434 kobiet i 201&#160;832 mężczyzn. Liczba gospodarstw domowych wynosiła 164&#160;248, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,52 osób.", "Zdrawko": "<b>Zdrawko</b> (Zdravko) – imię południowosłowiańskie utworzone od słowa „zdrowy”.", "Zofian": "<b>Zofian</b> – imię męskie pochodzące od żeńskiego imienia o greckim rodowodzie <b><a href=\"https://pl.wikipedia.org/wiki/Zofia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Zofia</a></b>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zhili": "<i>Zhili</i> oznacza \"[obszar] bezpośrednio rządzony\"; mianem tym za wczesnej dynastii Ming określano dwa obszary, które ze względu na swoje znaczenie gospodarcze i obronne zarządzane były bezpośrednio przez dwór cesarski:", "Zlatibor": "Zlatibor jest położony w północnej części regionu Stari Vlah, historycznej granicy między regionami <a href=\"https://pl.wikipedia.org/wiki/Ra%C5%A1ka\" target=\"_blank\" rel=\"noopener noreferrer\">Rašką</a>, <a href=\"https://pl.wikipedia.org/wiki/Hercegowina\" target=\"_blank\" rel=\"noopener noreferrer\">Hercegowiną</a> i <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%9Bnia_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Bośnią</a>. Szczyt <a href=\"https://pl.wikipedia.org/wiki/Cigla\" target=\"_blank\" rel=\"noopener noreferrer\">Cigla</a> w pobliżu wsi jest szczytem granicznym pomiędzy <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Serbii\" target=\"_blank\" rel=\"noopener noreferrer\">Królestwem Serbii</a>, <a href=\"https://pl.wikipedia.org/wiki/Austro-W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">Austro-Węgrami</a> i <a href=\"https://pl.wikipedia.org/wiki/Imperium_Osma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imperium Osmańskim</a>. W starożytności Zlatibor był nazywany <b>Rujno</b>, a <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupa_(jednostka_administracyjna)\" target=\"_blank\" rel=\"noopener noreferrer\">żupa</a> była częścią Raški. Nazwa Zlatibor pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>, ale jej etymologia jest wątpliwa. Najbardziej prawdopodobną wersją jest połączenie dwóch serbskich słów <i>zlatni</i> (złoty) i <i>bor</i> (sosna).", "Zek": "<b>Zek</b> – wywodzące się z socjolektu łagrowego ogólne określenie na więźnia systemu <a href=\"https://pl.wikipedia.org/wiki/Gu%C5%82ag\" target=\"_blank\" rel=\"noopener noreferrer\">Gułagu</a> w <a href=\"https://pl.wikipedia.org/wiki/Zwi%C4%85zek_Socjalistycznych_Republik_Radzieckich\" target=\"_blank\" rel=\"noopener noreferrer\">ZSRR</a>. Nazwa pochodzi od skrótu <i>z/k</i> stosowanego w państwowych dokumentach oznaczającego osobę uwięzioną.", "Zbrosław": "<b>Zbrosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Zbro-</i> (<i>borti</i> - „walczyć”, „zmagać się”) i <i>-sław</i> („sława”). Oznacza ono „tego, czyja sława tworzy się dzięki walce”. Jedną z form skróconych tego imienia był <a href=\"https://pl.wikipedia.org/wiki/Bros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Brosław</a>.", "Zuzanna": "<b>Zuzanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשַׁנָּה&#8206; (<i>szoszana</i>), zapożyczonego przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשָׁן&#8206; (<i>szoszan</i>), oznaczającego „lilia”, co z kolei prawdopodobnie wywodziło się od egipskiego <i>seszen</i>, czyli „lotos”. W Polsce imię to jest notowane w dokumentach od 1265 roku, w formach Zuzanna/Żużanna, a także pochodnych: Zanna/Żanna, Zanka/Zańka, Ożanka (zob. też <a href=\"https://pl.wikipedia.org/wiki/O%C5%BCanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożanna</a>), Zużka, Zuchna, Oszka. Wśród imion nadawanych nowo narodzonym dzieciom, Zuzanna w 2017 zajmowała 2. miejsce w grupie imion żeńskich.", "Zorzan": "<b>Zoran</b> (<a href=\"https://pl.wikipedia.org/wiki/Cyrylica_serbska\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylica serbska</a>: Зоран) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskie</a>, wywodzące się od słowa <i>zora</i> czyli „zorza, świt, jutrznia”.", "Zephyr": "Protokół umożliwia przesyłanie komunikatów podzielonych na rodzaje (<a href=\"https://pl.wikipedia.org/wiki/Klasa_(programowanie_obiektowe)\" target=\"_blank\" rel=\"noopener noreferrer\">klasy</a> i ich <a href=\"https://pl.wikipedia.org/wiki/Instancja_(programowanie)\" target=\"_blank\" rel=\"noopener noreferrer\">instancje</a>). Istnieje możliwość odbierania wyłącznie wybranych klas komunikatów. Protokół umożliwia również sprawdzanie, czy inny użytkownik jest obecny w systemie, z jakiej stacji sieciowej korzysta, oraz otrzymywanie informacji o logowaniu się i wylogowywaniu się użytkowników z systemu. Użytkownicy mogą określić na ile ich obecność w systemie ma być widoczna dla innych użytkowników. Komunikaty systemu są nazywane „zefirami” <i>(zephyrs)</i>, „zefirogramami” <i>(zephyrgrams)</i>, „oknogramami” <i>(zephyr windowgrams)</i> i są w przenoszą proste wiadomości tekstowe lub informacje o zdarzeniach.", "Zinaida": "<b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zbygniew": "<b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zebedeusz": "Imię Zebedeusz oznacza <i><a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> dał</i>.", "Zdzisława": "<b>Zdzisława</b>, <i><b>Zdziesława</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zdzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zdzisław</a>. Patronką tego imienia w Kościele katolickim jest bł. Zdzisława Czeska, patronka młodych małżeństw i matek.", "Żaneta": "<b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Zenona": "<b>Zenona</b> – imię żeńskie greckiego pochodzenia, odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zenon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Zenon</a>.", "Zenobia": "<b>Zenobia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zenobiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Zenobiusz</a>, złożonego z członów <i>Dzeno-</i> (<a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">homerycka</a> forma imienia <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>) i <i>bios</i> („życie”). Zenobia jest zatem <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">imieniem teoforycznym</a>. Patronką tego imienia jest św. Zenobia, siostra św. <a href=\"https://pl.wikipedia.org/wiki/Zenobiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Zenobiusza</a>, żyjąca w czasach cesarza <a href=\"https://pl.wikipedia.org/wiki/Dioklecjan\" target=\"_blank\" rel=\"noopener noreferrer\">Dioklecjana</a>.", "Zyta": "<b>Zyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od pospolitego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a>&#160;<em>zitta</em>, z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>zita</em>, oznaczającego „dziewczynę”. Chrześcijańską patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Zyta_z_Lukki\" target=\"_blank\" rel=\"noopener noreferrer\">Zyta z Lukki</a>, która jako jedyna wprowadziła to imię do kalendarzy. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/27_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 kwietnia</a>.", "Żaklina": "<b>Żaklina</b> – spolszczenie francuskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Jacqueline</i>, zapisane fonetycznie, które jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a>. Jest również inny żeński odpowiednik tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Jakubina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakubina</a>. Niektórzy błędnie uważają to imię za żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jacek\" target=\"_blank\" rel=\"noopener noreferrer\">Jacek</a> (mylnie interpretując francuskie imię <i>Jacques</i>).", "Żanna": "<b>Żanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, powstałe najprawdopodobniej pod wpływem rosyjskim, przez fonetyczne zapisanie francuskiej wersji imienia <b><a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a></b>, czyli <i>Jeanne</i>.", "Zenaida": "<b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zbigniewa": "<b>Zbygniewa</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zbigniew\" target=\"_blank\" rel=\"noopener noreferrer\">Zbygniew</a>. Złożone jest z dwóch członów: <i>Zby-</i> (\"zbyć, zbyć się, pozbyć się\") i <i>-gniewa</i> (\"gniew\"). Oznacza prawdopodobnie \"tę, która się zbyła (pozbyła) gniewu\". Istnieje też tłumaczenie alternatywne: „miej zbytek (nadmiar) gniewu” (gniew – jako zapał wojenny – był uważany za cnotę).", "Zefiryna": "<b>Zefiryna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zefiryn\" target=\"_blank\" rel=\"noopener noreferrer\">Zefiryn</a>. Jest to imię <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>, utworzone za pomocą sufiksu <i>-inus</i> od imienia greckiego boga wiatru zachodniego (<i>Zéphyros</i>).", "Zygfryda": "<b>Zygfryda</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zygfryd\" target=\"_blank\" rel=\"noopener noreferrer\">Zygfryd</a>. Wywodzi się od słów <i>sigu</i> i <i>fridu</i> oznaczających <i>zwycięstwo</i> i <i>pokój</i>, a zatem imię to może oznaczać „zaprowadzająca pokój dzięki zwycięstwu”. Patronami tego imienia są św. Zygfrydowie.", "Żywia": "<b>Żywia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia słowiańskiego. Imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Siwa_(bogini_s%C5%82owia%C5%84ska)\" target=\"_blank\" rel=\"noopener noreferrer\">Żywii</a>, słowiańskiej bogini życia, płodności i wiosny.", "Zygmunta": "<b>Zygmunta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zygmunt\" target=\"_blank\" rel=\"noopener noreferrer\">Zygmunt</a>. Wywodzi się od słów: <i>sigu</i> oznaczającego „zwycięstwo” i <i>munt</i> - „opieka”, czyli ta, której opieka zapewnia zwycięstwo.", "Zbysława": "<b>Zbysława</b> – żeński odpowiednik staropolskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zbys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zbysław</a>. Składa się z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-sława</i>.", "Zyglinda": "<b>Zyglinda</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a>, złożone z członów <i>sig</i> – \"zwycięstwo\" i <i>lind</i> – \"miękka, łagodna\" lub \"tarcza ochronna\". Patronką tego imienia jest św. Zyglinda (<a href=\"https://pl.wikipedia.org/wiki/Segolena\" target=\"_blank\" rel=\"noopener noreferrer\">Segolena</a>), <a href=\"https://pl.wikipedia.org/wiki/Opat\" target=\"_blank\" rel=\"noopener noreferrer\">ksieni</a> z Troclar (w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Albi\" target=\"_blank\" rel=\"noopener noreferrer\">Albi</a>).", "Żelisława": "<b>Żelisława</b> – staropolskie imię żeńskie; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%BBelis%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Żelisław</a>. Znaczenie imienia: \"pragnąca sławy\".", "Zula": "<b>Zuzanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשַׁנָּה&#8206; (<i>szoszana</i>), zapożyczonego przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשָׁן&#8206; (<i>szoszan</i>), oznaczającego „lilia”, co z kolei prawdopodobnie wywodziło się od egipskiego <i>seszen</i>, czyli „lotos”. W Polsce imię to jest notowane w dokumentach od 1265 roku, w formach Zuzanna/Żużanna, a także pochodnych: Zanna/Żanna, Zanka/Zańka, Ożanka (zob. też <a href=\"https://pl.wikipedia.org/wiki/O%C5%BCanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożanna</a>), Zużka, Zuchna, Oszka. Wśród imion nadawanych nowo narodzonym dzieciom, Zuzanna w 2017 zajmowała 2. miejsce w grupie imion żeńskich.", "Zulfiya": "Urodziła się w rodzinie <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">żydowskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Giser\" target=\"_blank\" rel=\"noopener noreferrer\">gisera</a>-chałupnika. Skończyła szkołę średnią i żeńską szkołę pedagogiczną, pracowała w redakcjach republikańskich gazet i pism, zaczęła pisać wiersze. W 1932, w wieku 17 lat, wydała swój pierwszy zbiór wierszy <i>Stranicy żyzni</i>, o młodzieży, przyjaźni i pięknie ludzkiej duszy. Od 1938 pracowała w różnych wydawnictwach, podczas <a href=\"https://pl.wikipedia.org/wiki/Front_wschodni_(II_wojna_%C5%9Bwiatowa)\" target=\"_blank\" rel=\"noopener noreferrer\">wojny ZSRR z Niemcami</a> pisała wiersze patriotyczne. W 1965 opublikowała zbiór wierszy <i>Kuylarim sizga</i> (<i>Śpiewam dla was</i>), a w 1971 poemat <i>Quyoshli qalam</i> (<i>Słoneczne pióro</i>). Pisała także artykuły prasowe o roli kobiety w rodzinie i społeczeństwie. Jej mężem był Hamid Olimjon, przewodniczący Związku Pisarzy Uzbekistanu. W Taszkencie jej imieniem nazwano ulicę, a w 2008 zbudowano jej pomnik. W 2004 ustanowiono Nagrodę Państwową im. Zulfiyi w dziedzinie literatury, sztuki, nauki, kultury i edukacji.", "Zenajda": "<b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zinajda": "<b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Żywila": "<b>Żywila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia literackiego. Tytułowa postać wczesnego utworu <a href=\"https://pl.wikipedia.org/wiki/Adam_Mickiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Adama Mickiewicza</a>, jak również opartej na nim opery <a href=\"https://pl.wikipedia.org/wiki/Alojzy_Dworzaczek\" target=\"_blank\" rel=\"noopener noreferrer\">Alojzego Dworzaczka</a> z <a href=\"https://pl.wikipedia.org/wiki/Libretto\" target=\"_blank\" rel=\"noopener noreferrer\">librettem</a> Bronisławy Wilkoszewskiej (premiera <a href=\"https://pl.wikipedia.org/wiki/12_maja\" target=\"_blank\" rel=\"noopener noreferrer\">12 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1926\" target=\"_blank\" rel=\"noopener noreferrer\">1926</a>). Prawdopodobnie powstało jako kontaminacja wymienionych w <i>Kronice</i> <a href=\"https://pl.wikipedia.org/wiki/Maciej_Stryjkowski\" target=\"_blank\" rel=\"noopener noreferrer\">Stryjkowskiego</a> imion dwóch pogańskich bóstw: <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywie\" target=\"_blank\" rel=\"noopener noreferrer\">Żywie</a>, bóstwa — wiatru, oraz <i>Zizilii</i>, bogini stanowiącej odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Wenus_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Wenery</a>.", "Żywisława": "<b>Żywisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> utworzony na wzór imion słowiańskich. Człon <i>Żywi-</i> jest niespotykany w staropolskich imionach dwuczłonowych.", "Zulfija": "Urodziła się w rodzinie <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">żydowskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Giser\" target=\"_blank\" rel=\"noopener noreferrer\">gisera</a>-chałupnika. Skończyła szkołę średnią i żeńską szkołę pedagogiczną, pracowała w redakcjach republikańskich gazet i pism, zaczęła pisać wiersze. W 1932, w wieku 17 lat, wydała swój pierwszy zbiór wierszy <i>Stranicy żyzni</i>, o młodzieży, przyjaźni i pięknie ludzkiej duszy. Od 1938 pracowała w różnych wydawnictwach, podczas <a href=\"https://pl.wikipedia.org/wiki/Front_wschodni_(II_wojna_%C5%9Bwiatowa)\" target=\"_blank\" rel=\"noopener noreferrer\">wojny ZSRR z Niemcami</a> pisała wiersze patriotyczne. W 1965 opublikowała zbiór wierszy <i>Kuylarim sizga</i> (<i>Śpiewam dla was</i>), a w 1971 poemat <i>Quyoshli qalam</i> (<i>Słoneczne pióro</i>). Pisała także artykuły prasowe o roli kobiety w rodzinie i społeczeństwie. Jej mężem był Hamid Olimjon, przewodniczący Związku Pisarzy Uzbekistanu. W Taszkencie jej imieniem nazwano ulicę, a w 2008 zbudowano jej pomnik. W 2004 ustanowiono Nagrodę Państwową im. Zulfiyi w dziedzinie literatury, sztuki, nauki, kultury i edukacji.", "Zarin": "Nazwa <a href=\"https://pl.wikipedia.org/wiki/Waluta\" target=\"_blank\" rel=\"noopener noreferrer\">waluty</a> w języku osetyjskim oznacza <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82oto\" target=\"_blank\" rel=\"noopener noreferrer\">złoto</a> i nawiązuje do historycznych pieniędzy używanych na terytoriach starożytnej <a href=\"https://pl.wikipedia.org/wiki/Scytia\" target=\"_blank\" rel=\"noopener noreferrer\">Scytii</a>, <a href=\"https://pl.wikipedia.org/wiki/Sarmaci\" target=\"_blank\" rel=\"noopener noreferrer\">Sarmacji</a>, <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Osetia\" target=\"_blank\" rel=\"noopener noreferrer\">Osetii</a>.", "Zwinisława": "<b>Zwnisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, składające się z członów <i>Zwni-</i> (prasłow. *<i>zvьněti</i> „brzmieć, dźwięczeć”, por. stpol. <i>zwonić</i>, współcz. <i>dzwonić</i> „wydawać dźwięk”) oraz <i>-sława</i> (por. <i>sława</i>, <i>sławić</i>).", "Zetta": "W <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyce</a> oznacza on częściej 2 = 1024 = 1 180 591 620 717 411 303 424, np. 1ZB (<a href=\"https://pl.wikipedia.org/wiki/Zettabajt\" target=\"_blank\" rel=\"noopener noreferrer\">zettabajt</a>) to 2 <a href=\"https://pl.wikipedia.org/wiki/Bajt\" target=\"_blank\" rel=\"noopener noreferrer\">bajtów</a>.", "Zwienisława": "<b>Zwnisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, składające się z członów <i>Zwni-</i> (prasłow. *<i>zvьněti</i> „brzmieć, dźwięczeć”, por. stpol. <i>zwonić</i>, współcz. <i>dzwonić</i> „wydawać dźwięk”) oraz <i>-sława</i> (por. <i>sława</i>, <i>sławić</i>).", "Zin": "<b>Zin</b>, <b>fanzin</b> (skrót od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>fan magazine</em>) – rodzaj nieprofesjonalnego pisma tworzonego przez osobę bądź grupę osób – miłośników jakiegoś tematu (np. <a href=\"https://pl.wikipedia.org/wiki/Muzyka\" target=\"_blank\" rel=\"noopener noreferrer\">muzyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Literatura\" target=\"_blank\" rel=\"noopener noreferrer\">literatury</a>, <a href=\"https://pl.wikipedia.org/wiki/Fantastyka\" target=\"_blank\" rel=\"noopener noreferrer\">fantastyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Gra_fabularna\" target=\"_blank\" rel=\"noopener noreferrer\">gier fabularnych</a>, <a href=\"https://pl.wikipedia.org/wiki/Ekologia\" target=\"_blank\" rel=\"noopener noreferrer\">ekologii</a>, <a href=\"https://pl.wikipedia.org/wiki/Polityka\" target=\"_blank\" rel=\"noopener noreferrer\">polityki</a>), skierowane do osób podzielających owe zainteresowania.", "Zamzam": "<b>Zamzam, Zemzem</b> – święta studnia w <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekce</a> w pobliżu świątyni <a href=\"https://pl.wikipedia.org/wiki/Al-Kaba\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Kaba</a>; według tradycji powstała w czasach <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>. Tradycja mówi, że w jej miejscu w czasach proroka wytrysnęło źródło, gdy <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> pozostawiona na pustyni z małym synem <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaelem</a> rozpaczliwie poszukiwała wody. Nazwa tego źródła wywodzi się od arabskiego słowa <i>zam</i> (<i>dość</i>), ponieważ, gdy woda tryskała z ziemi pod wysokim ciśnieniem, Hagar krzyczała właśnie „dość, dość”. Później studnia została zapomniana i zasypana. Ponownie odkrył ją dziadek <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a>, Abd al-Muttalib. Obecnie odwiedzana przez pielgrzymów muzułmańskich podczas <a href=\"https://pl.wikipedia.org/wiki/Had%C5%BCd%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">hadżdżu</a>. Picie wody z Zamzamu jest obyczajem religijnym zapewniającym zdrowie wiernego. Wodę z Zamzamu przechowuje się w specjalnych buteleczkach zwanych zamzamijja."};
